package com.ruoyi.modules.invest.benefit.calculation.service.impl;
import com.ruoyi.common.utils.DateUtils;import com.ruoyi.common.utils.ShiroUtils;import com.ruoyi.modules.invest.benefit.calculation.domain.*;import com.ruoyi.modules.invest.benefit.calculation.mapper.*;import com.ruoyi.modules.invest.benefit.calculation.service.IInvestBenefitCalculationService;import com.ruoyi.modules.invest.project.domain.InvestProject;import com.ruoyi.modules.invest.project.mapper.InvestProjectMapper;import com.ruoyi.modules.invest.workflow.BpmnProcessService;import org.flowable.engine.runtime.ProcessInstance;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.math.*;import java.util.*;@Service public class InvestBenefitCalculationServiceImpl implements IInvestBenefitCalculationService{@Autowired private InvestBenefitCalculationMapper mapper;@Autowired private InvestBenefitCalcItemMapper itemMapper;@Autowired private InvestProjectMapper projectMapper;@Autowired private BpmnProcessService bpmn;public InvestBenefitCalculation selectById(Long id){InvestBenefitCalculation c=mapper.selectById(id);if(c!=null)c.setItemList(itemMapper.selectByCalcId(id));return c;}public List<InvestBenefitCalculation> selectList(InvestBenefitCalculation c){return mapper.selectList(c);}@Transactional public int insert(InvestBenefitCalculation c){fillProject(c);c.setCreateBy(ShiroUtils.getLoginName());c.setCreateTime(DateUtils.getNowDate());c.setDelFlag("0");if(c.getCalcStatus()==null)c.setCalcStatus("0");if(c.getCalcCode()==null||c.getCalcCode().isEmpty())c.setCalcCode("BEN-"+System.currentTimeMillis());calcCore(c);return mapper.insert(c);}@Transactional public int update(InvestBenefitCalculation c){fillProject(c);c.setUpdateBy(ShiroUtils.getLoginName());c.setUpdateTime(DateUtils.getNowDate());calcCore(c);return mapper.update(c);}public int deleteByIds(Long[] ids){for(Long id:ids)itemMapper.deleteByCalcId(id);return mapper.deleteByIds(ids);}@Transactional public int saveItems(Long calcId,List<InvestBenefitCalcItem> items){itemMapper.deleteByCalcId(calcId);BigDecimal score=BigDecimal.ZERO;int rows=0;if(items!=null)for(InvestBenefitCalcItem it:items){it.setCalcId(calcId);BigDecimal s=it.getScore()==null?BigDecimal.ZERO:it.getScore();BigDecimal w=it.getWeight()==null?BigDecimal.ZERO:it.getWeight();it.setWeightedScore(s.multiply(w).divide(new BigDecimal("100"),2,RoundingMode.HALF_UP));score=score.add(it.getWeightedScore());rows+=itemMapper.insert(it);}InvestBenefitCalculation c=new InvestBenefitCalculation();c.setCalcId(calcId);c.setBenefitScore(score);c.setUpdateBy(ShiroUtils.getLoginName());c.setUpdateTime(DateUtils.getNowDate());mapper.update(c);return rows;}public boolean calculate(Long calcId){InvestBenefitCalculation c=selectById(calcId);if(c==null)return false;calcCore(c);return mapper.update(c)>0;}public boolean submit(Long calcId){InvestBenefitCalculation c=selectById(calcId);if(c==null)return false;try{Map<String,Object> v=new HashMap<>();v.put("calcId",calcId);ProcessInstance pi=bpmn.startProcess("benefit_calculation_approval",String.valueOf(calcId),v);c.setProcessInstanceId(pi.getId());}catch(Exception e){c.setProcessInstanceId(null);}c.setCalcStatus("1");c.setUpdateBy(ShiroUtils.getLoginName());c.setUpdateTime(DateUtils.getNowDate());return mapper.update(c)>0;}private void calcCore(InvestBenefitCalculation c){BigDecimal invest=c.getInvestAmount()==null?BigDecimal.ZERO:c.getInvestAmount();BigDecimal profit=c.getExpectedProfit()==null?BigDecimal.ZERO:c.getExpectedProfit();c.setRoi(invest.compareTo(BigDecimal.ZERO)==0?BigDecimal.ZERO:profit.multiply(new BigDecimal("100")).divide(invest,2,RoundingMode.HALF_UP));}private void fillProject(InvestBenefitCalculation c){if(c.getProjectId()==null)return;InvestProject p=projectMapper.selectInvestProjectById(c.getProjectId());if(p!=null){c.setProjectCode(p.getProjectCode());c.setProjectName(p.getProjectName());c.setSchemeId(p.getSchemeId());if(c.getInvestAmount()==null)c.setInvestAmount(p.getInvestedAmount()!=null?p.getInvestedAmount():p.getProposedAmount());}}}